<template>
  <div class="timeRemind">
    <article>
      <p v-show="restTime.length >= 2" v-for="(item, i) in restTime" :key="i">
        距离 {{ item[0] }} 还剩
        <strong :class="{notActive: item[1] === '00:00:00'}">{{ item[1] }}</strong>
      </p>
    </article>
  </div>
</template>

<script>
export default {
  data() { return {
    restTime: [
      ['moment', 'diff']
    ],
    timer: NaN
  }},

  computed: {
    currentDate() {
      let today = new Date();
      let result = [
        today.getFullYear(),
        today.getMonth(),
        today.getDate()
      ];
      return result;
    },
    moments() {
      let result = [];
      for (let i = 0; i < 25; i += 6) {
        if (i === 0) {
          continue;
        }
        result.push([i, 0, 0]);
      }
      return result;
      
      
    },
    momentsTimestamp() {
      let result = [];
      this.moments.forEach((value) => {
        let item = [...this.currentDate, ...value];
        result.push(new Date(...item).getTime());
      });
      return result;
    },
    momentsString() {
      let result = [];
      this.moments.forEach((value) => {
        let h = this.transtoTwo(value[0]);
        result.push(`${h}:00`);
      });
      return result;
    }
  },

  methods: {
    transtoTwo(number) {
      if (number < 10) {
        return `0${number}`;
      } else {
        return `${number}`;
      }
    },
    calTimeDiff(currentTimestamp, momentsTimestamp) {
      let result = [];

      momentsTimestamp.forEach((value) => {
        let diff = value - currentTimestamp;
        if (diff <= 1000) {
          diff = 0;
        }
        result.push(diff);
      });
      return result;
    },
    difftoTime(ms) {
      let hour = this.transtoTwo(Math.floor(ms / 1000 / 60 / 60)),
        minute = this.transtoTwo(Math.floor(ms / 1000 / 60 % 60)),
        second = this.transtoTwo(Math.floor(ms / 1000 % 60));
      
      return `${hour}:${minute}:${second}`;
    },
    getRestTime() {
      let result = [];
      let diffs = [];
      this.calTimeDiff(Date.now(), this.momentsTimestamp)
        .forEach((diff) => {
          let item = '';
          if (diff === 0) {
            item = '00:00:00';
          } else {
            item = this.difftoTime(diff);
          }
          diffs.push(item);
        });
      
      for (let i = 0; i < this.moments.length; i++) {
        let item = [this.momentsString[i], diffs[i]];
        result.push(item);
      }
      this.restTime = result;
    }
  },

  mounted() {
    this.timer = setInterval(() => {
      this.getRestTime();
    }, 1000);
  },

  beforeDestroy() {
    clearInterval(this.timer);
  }
}
</script>

<style lang="scss" scoped>
@import '@/common/_public.scss';

div.timeRemind {
  color: $subtext;
  // font-size: ($sz-normal * 1.25);
  text-align: center;

  article {
    display: inline-block;
    text-align: left;
  }
  p {
    margin-bottom: ($sz-normal * 1.5);
  }
  strong.notActive {
    font-weight: 400;
  }
}

</style>