<template>
  <div class="weather">
    <article>
      <section class="weatherInfo">
        <p>天气</p>
      </section>
      <section class="detailInfo">
        <p>温度</p>
        <p>预警</p>
        <p>
          {{ city }}
          <span class="edit" @click="editCity()">edit</span>
        </p>
      </section>
    </article>

    <modal :showModal="showModal" @close-modal="closeModal()">
      <form>
        <input type="text" v-model="inputCity">
      </form>
    </modal>
  </div>
</template>

<script>
/* 
* ▶ 接口
* 1 city 城市：默认深圳，可读取修改值。何时用计算属性？何时用 data + mounted？
* 2 current
*/
import Modal from './Modal';

export default {
  components: {
    'modal': Modal
  },

  data() { return {
    city: '',
    inputCity: '',
    showModal: false,
  }},

  methods: {
    loadCity() {
      if (localStorage.currentCity) {
        // 格式：深圳市-shenzhen
        this.city = localStorage.currentCity;
        return;
      }
      
      this.city = '深圳市';
    },
    editCity() {
      this.showModal = true;
    },
    closeModal() {
      this.showModal = false;
      this.inputCity = '';
    }
  },

  mounted() {
    this.loadCity();
  },

  watch: {
    inputCity: {
      immediate: true,
      handler(val, oldVal) {
        if (val !== '') {
          this.city = val;
          localStorage.setItem('currentCity', val);
          return;
        }
      }
    }
  }
}
</script>

<style lang="scss" scoped>
@import '@/common/_public.scss';

div.weather {
  box-sizing: border-box;
  width: 100%;
  max-width: 400px;
  background: $lightprim;
  color: $content;
  @include padding(1, 1);
  border-radius: ($sz-normal / 4);
  margin: 0 auto;

  article {
    display: grid;
    grid-template-columns: 3fr 5fr;
  }
  span.edit {
    color: $subtext;
    text-decoration: underline;
    cursor: pointer;
  }
  section.weatherInfo {
    display: grid;
    place-items: center center;
    padding-right: ($sz-normal * 2);
  }
  section.detailInfo {
    padding-left: ($sz-normal * 2);
  }
}
</style>