<template>
  <div class="modal" v-if="showModal" @click.self="$emit('close-modal')">
    <slot></slot>
  </div>
</template>

<script>
/* 
* ○ 点击内部不隐藏，点击外部隐藏：@click.self
* ○ 控制 modal 的显示与隐藏：
*/
export default {
  props: {
    showModal: {
      type: Boolean,
      default: false
    }
  }
}
</script>

<style lang="scss" scoped>
@import '@/common/_public.scss';

div.modal {
  display: flex;
  flex-flow: column nowrap;
  justify-content: center;
  align-items: center;
  position: fixed;
  bottom: 0;
  left: 0;
  z-index: 1000;
  width: 100vw;
  height: 100vh;
  & > * {
    display: grid;
    place-items: center center;
    width: 50%;
    height: 50%;
    background: #ffffff;
    @include box-shadow(0, 0, 2, -0.2, $shadow);
  }
}
</style>