<template>
  <div class="today">
    <article>
      <p class="week">{{ currentWeek }}</p>
      <p class="date">{{ currentDate }}</p>
    </article>
  </div>
</template>

<script>
export default {
  data() { return {
    currentDay: new Date()
  }},

  computed: {
    currentWeek() {
      const weekSheet = ['周日', '周一', '周二',
        '周三', '周四', '周五', '周六'];
      
      return weekSheet[this.currentDay.getDay()];
    },
    currentDate() {
      const result = this.currentDay.toLocaleDateString();

      return result;
    }
  },
}
</script>

<style lang="scss" scoped>
@import '@/common/_public.scss';

div.today {
  box-sizing: border-box;
  width: 100%;
  max-width: 400px;
  background: $lighthigh;
  color: $content;
  @include padding(1, 1);
  border-radius: ($sz-normal / 4);
  margin: 0 auto;

  p {
    text-align: center;
  }
}
</style>